parameters.jsCode:
// n8n Code Node
return items.map(item => {
  let raw = item.json.output || item.json; 

  if (typeof raw === "string") {
    // Remove markdown fences (```json ... ```)
    raw = raw.replace(/```json|```/g, "").trim();

    // Try to parse the JSON string
    try {
      raw = JSON.parse(raw);
    } catch (e) {
      raw = { error: "Invalid JSON", raw: raw };
    }
  }

  return { json: raw };
});

// Remove unwanted fields, keep only input_fields + output_requirements
return [{
  input_fields:$input.first().json.raw
  output_requirements: $input.first().json.product_marketing_prompt_generator.output_requirements
}];
